def main():
    subjects = {}
    for f in sorted(os.listdir(GRADE_DIR)):
        if f.endswith('.json') and f != '_bundle.json':
            filepath = os.path.join(GRADE_DIR, f)
            with open(filepath, 'r', encoding='utf-8') as fh:
                data = json.load(fh)
            subject_key = f.replace('.json', '')
            subjects[subject_key] = data

    total_games_added = 0
    total_tasks_added = 0

    for key, data in sorted(subjects.items()):
        lessons_data = data.get('lessons', data)
        title = lessons_data.get('title', key)
        topics = lessons_data.get('detailedTopics', lessons_data.get('topics', []))
        meta = SUBJECT_META.get(key, {"icon": "Book", "color": "text-blue-400", "name": title})

        # Check if games already exist
        existing_games = lessons_data.get('games', [])
        if existing_games:
            print(f"  {key}: already has {len(existing_games)} games, skipping")
            continue

        # Build games from quiz data
        games = []
        quiz_topics = QUIZ_DATA.get(key, {})

        for topic in topics:
            if not isinstance(topic, dict):
                continue
            topic_name = topic.get('topic', '')
            topic_lessons = topic.get('lessons', [])

            # Find matching quiz data by topic name substring match
            quiz_tasks = None
            for qkey, qtasks in quiz_topics.items():
                if qkey in topic_name or topic_name in qkey:
                    quiz_tasks = qtasks
                    break

            if not quiz_tasks:
                # Generate generic quiz tasks based on lesson content
                quiz_tasks = []
                for i, lesson in enumerate(topic_lessons):
                    lesson_title = lesson.get('title', '')
                    lesson_desc = lesson.get('description', '')
                    # Create a simple quiz from lesson info
                    q = {
                        "type": "quiz",
                        "question": f"Что вы узнали на уроке «{lesson_title.replace(chr(10),'')}»?",
                        "options": [lesson_desc[:50] if lesson_desc else "Изучили новую тему", "Повторили старое", "Ничего не делали", "Играли в игры", "Смотрели фильм", "Гуляли"],
                        "correctAnswer": lesson_desc[:50] if lesson_desc else "Изучили новую тему",
                        "hint": f"Вспомните тему урока"
                    }
                    quiz_tasks.append(q)

            # Create game
            game_title = f"{topic_name} {'📖' if 'литератур' in title.lower() else '📝'}"
            game = {
                "title": game_title[:50],
                "subject": meta["name"],
                "icon": meta["icon"],
                "color": meta["color"],
                "tasks": quiz_tasks[:5],  # Max 5 tasks per game
                "reward": {
                    "stars": 3,
                    "message": f"Отлично! Ты знаешь «{topic_name}»! 🌟"
                }
            }
            games.append(game)
            total_games_added += 1
            total_tasks_added += len(quiz_tasks[:5])

        # Add games to the data
        lessons_data['games'] = games

        # Save
        filepath = os.path.join(GRADE_DIR, f"{key}.json")
        with open(filepath, 'w', encoding='utf-8') as fh:
            json.dump(data, fh, ensure_ascii=False, indent=2)

        print(f"  ✅ {key}: added {len(games)} games ({total_tasks_added} tasks so far)")

    # Update _bundle.json
    bundle_path = os.path.join(GRADE_DIR, "_bundle.json")
    if os.path.exists(bundle_path):
        with open(bundle_path, 'r', encoding='utf-8') as fh:
            bundle = json.load(fh)
        
        for key in subjects:
            if key in bundle:
                bundle[key]['lessons']['games'] = subjects[key]['lessons'].get('games', [])
        
        with open(bundle_path, 'w', encoding='utf-8') as fh:
            json.dump(bundle, fh, ensure_ascii=False, indent=2)
        print(f"\n  ✅ Updated _bundle.json")

    print(f"\n{'='*60}")
    print(f"TOTAL: {total_games_added} games, {total_tasks_added} quiz tasks added")

if __name__ == "__main__":
    main()
